+.ars_intersections <- function(x, h, hp, domain, tolerance) {
+  k <- length(x)
+  z <- numeric(k + 1L)
+  z[1L] <- domain[1L]
+  z[k + 1L] <- domain[2L]
+
+  for (i in seq_len(k - 1L)) {
+    denom <- hp[i] - hp[i + 1L]
+    if (abs(denom) <= tolerance) {
+      .ars_stop("parallel tangent lines encountered; log-density is not strictly concave at support points.")
+    }
+    z[i + 1L] <- (h[i + 1L] - h[i] - x[i + 1L] * hp[i + 1L] +
+                    x[i] * hp[i]) / denom
+  }
+
+  if (any(!is.finite(z[-c(1L, length(z))])) || any(diff(z) <= -tolerance)) {
+    .ars_stop("non-log-concave density detected: tangent intersections are not ordered.")
+  }
+
+  z
+}
