+.ars_sample_from_upper <- function(state, tolerance) {
+  log_weights <- .ars_interval_log_weights(state, tolerance)
+  max_log_weight <- max(log_weights)
+  probs <- exp(log_weights - max_log_weight)
+  probs <- probs / sum(probs)
+  interval <- sample.int(length(probs), size = 1L, prob = probs)
+  y <- .ars_sample_exp_interval(
+    state$hp[interval], state$z[interval], state$z[interval + 1L], tolerance
+  )
+  list(x = y, interval = interval)
