+  lower <- domain[1L]
+  upper <- domain[2L]
+  samples <- numeric(n)
+  for (i in seq_len(n)) {
+    samples[i] <- .ars_sample_exp_interval(slope, lower, upper, tolerance)
+  }
+  samples
