/app/ars.R.content:
# Adaptive rejection sampling for univariate log-concave densities.
# Reference: Gilks and Wild (1992), Applied Statistics, 41(2), 337-348.

.ars_stop <- function(...) {
  stop(paste0(...), call. = FALSE)
}

.ars_as_density_function <- function(density, env) {
  if (is.function(density)) {
    return(density)
  }

  if (inherits(density, "formula")) {
    expr <- density[[length(density)]]
    return(function(x) eval(expr, envir = list(x = x), enclos = env))
  }

  if (is.expression(density)) {
    expr <- density[[1L]]
    return(function(x) eval(expr, envir = list(x = x), enclos = env))
  }

  if (is.character(density) && length(density) == 1L) {
    expr <- parse(text = density)[[1L]]
    return(function(x) eval(expr, envir = list(x = x), enclos = env))
  }

  .ars_stop("density must be a function, formula, expression, or single expression string.")
}

.ars_validate_inputs <- function(n, density, domain, initial, derivative_step,
                                 max_iter, tolerance) {
  if (!is.numeric(n) || length(n) != 1L || !is.finite(n) || n != floor(n) || n <= 0) {
    .ars_stop("n must be a single positive integer.")
  }
  if (!is.numeric(domain) || length(domain) != 2L || any(is.na(domain)) ||
      domain[1L] >= domain[2L]) {
    .ars_stop("domain must be c(lower, upper) with lower < upper.")
  }
  if (!is.null(initial)) {
    if (!is.numeric(initial) || length(initial) < 2L || any(!is.finite(initial))) {
      .ars_stop("initial must contain at least two finite numeric support points.")
    }
    if (any(initial <= domain[1L]) || any(initial >= domain[2L])) {
      .ars_stop("all initial support points must lie strictly inside the domain.")
    }
  }
  if (!is.numeric(derivative_step) || length(derivative_step) != 1L ||
      !is.finite(derivative_step) || derivative_step <= 0) {
    .ars_stop("derivative_step must be a positive finite number.")
  }
  if (!is.numeric(max_iter) || length(max_iter) != 1L || !is.finite(max_iter) ||
      max_iter < n) {
    .ars_stop("max_iter must be a finite number at least as large as n.")
  }
  if (!is.numeric(tolerance) || length(tolerance) != 1L || !is.finite(tolerance) ||
      tolerance <= 0) {
    .ars_stop("tolerance must be a positive finite number.")
  }
  invisible(TRUE)
}

.ars_default_initial <- function(domain) {
  lower <- domain[1L]
  upper <- domain[2L]

  if (is.finite(lower) && is.finite(upper)) {
    return(lower + c(0.25, 0.5, 0.75) * (upper - lower))
  }
  if (is.finite(lower)) {
    scale <- max(1, abs(lower))
    return(lower + c(0.25, 1, 2) * scale)
  }
  if (is.finite(upper)) {
    scale <- max(1, abs(upper))
    return(upper - c(2, 1, 0.25) * scale)
  }
  c(-1, 0, 1)
}

.ars_log_density_factory <- function(density_function, log_density) {
  force(density_function)
  force(log_density)

  function(x) {
    value <- density_function(x)
    if (!is.numeric(value) || length(value) != length(x)) {
      .ars_stop("density must return a numeric vector with the same length as x.")
    }
    if (any(is.na(value))) {
      .ars_stop("density returned NA values.")
    }
    if (log_density) {
      return(value)
    }
    if (any(value < 0, na.rm = TRUE)) {
      .ars_stop("density returned negative values.")
    }
    log(value)
  }
}

.ars_eval_log_density <- function(log_density_function, x) {
  h <- log_density_function(x)
  if (!is.numeric(h) || length(h) != length(x) || any(is.na(h))) {
    .ars_stop("log-density evaluation failed.")
  }
  h
}

.ars_numeric_derivative <- function(log_density_function, x, domain,
                                    derivative_step) {
  vapply(x, function(xi) {
    step <- derivative_step * max(1, abs(xi))
    lower <- domain[1L]
    upper <- domain[2L]

    if (is.finite(lower) && xi - step <= lower) {
      right <- min(xi + step, upper - .Machine$double.eps^0.5)
      left <- xi
      return((.ars_eval_log_density(log_density_function, right) -
                .ars_eval_log_density(log_density_function, left)) / (right - left))
    }

    if (is.finite(upper) && xi + step >= upper) {
      left <- max(xi - step, lower + .Machine$double.eps^0.5)
      right <- xi
      return((.ars_eval_log_density(log_density_function, right) -
                .ars_eval_log_density(log_density_function, left)) / (right - left))
    }

    (.ars_eval_log_density(log_density_function, xi + step) -
       .ars_eval_log_density(log_density_function, xi - step)) / (2 * step)
  }, numeric(1L))
}

.ars_check_support <- function(x, h, hp, tolerance) {
  if (any(!is.finite(h))) {
    .ars_stop("initial/support points must have positive finite density.")
  }
  if (any(!is.finite(hp))) {
    .ars_stop("log-density derivative must be finite at all support points.")
  }

  slope_diffs <- diff(hp)
  if (any(slope_diffs > tolerance)) {
    .ars_stop("non-log-concave density detected: log-density slopes increased.")
  }

  invisible(TRUE)
}

.ars_intersections <- function(x, h, hp, domain, tolerance) {
  k <- length(x)
  z <- numeric(k + 1L)
  z[1L] <- domain[1L]
  z[k + 1L] <- domain[2L]

  for (i in seq_len(k - 1L)) {
    denom <- hp[i] - hp[i + 1L]
    if (abs(denom) <= tolerance) {
      .ars_stop("parallel tangent lines encountered; log-density is not strictly concave at support points.")
    }
    z[i + 1L] <- (h[i + 1L] - h[i] - x[i + 1L] * hp[i + 1L] +
                    x[i] * hp[i]) / denom
  }

  if (any(!is.finite(z[-c(1L, length(z))])) || any(diff(z) <= -tolerance)) {
    .ars_stop("non-log-concave density detected: tangent intersections are not ordered.")
  }

  z
}

.ars_build_state <- function(x, h, hp, domain, tolerance) {
  ordering <- order(x)
  x <- x[ordering]
  h <- h[ordering]
  hp <- hp[ordering]

  .ars_check_support(x, h, hp, tolerance)
  z <- .ars_intersections(x, h, hp, domain, tolerance)
  list(x = x, h = h, hp = hp, z = z, domain = domain)
}

.ars_is_affine_log_density <- function(x, h, hp, tolerance) {
  if (length(x) < 2L) {
    return(FALSE)
  }
  slopes_equal <- max(abs(hp - hp[1L])) <= sqrt(tolerance)
  intercepts <- h - hp * x
  intercepts_equal <- max(abs(intercepts - intercepts[1L])) <= 100 * sqrt(tolerance)
  slopes_equal && intercepts_equal
}

.ars_log_interval_integral <- function(slope, intercept, lower, upper, tolerance) {
  if (abs(slope) <= tolerance) {
    if (!is.finite(lower) || !is.finite(upper)) {
      .ars_stop("flat envelope over an infinite interval is not integrable.")
    }
    return(intercept + log(upper - lower))
  }

  if (slope > 0) {
    if (!is.finite(upper)) {
      .ars_stop("envelope is not integrable on the upper tail; choose better support points/domain.")
    }
    if (is.infinite(lower)) {
      return(intercept + slope * upper - log(slope))
    }
    return(intercept + slope * upper +
             log1p(-exp(slope * (lower - upper))) - log(slope))
  }

  if (!is.finite(lower)) {
    .ars_stop("envelope is not integrable on the lower tail; choose better support points/domain.")
  }
  if (is.infinite(upper)) {
    return(intercept + slope * lower - log(-slope))
  }
  intercept + slope * lower +
    log1p(-exp(slope * (upper - lower))) - log(-slope)
}

.ars_interval_log_weights <- function(state, tolerance) {
  k <- length(state$x)
  weights <- numeric(k)
  for (i in seq_len(k)) {
    intercept <- state$h[i] - state$hp[i] * state$x[i]
    weights[i] <- .ars_log_interval_integral(
      state$hp[i], intercept, state$z[i], state$z[i + 1L], tolerance
    )
  }
  weights
}

.ars_sample_exp_interval <- function(slope, lower, upper, tolerance) {
  u <- runif(1L)
  if (abs(slope) <= tolerance) {
    return(runif(1L, lower, upper))
  }

  if (slope > 0) {
    if (is.infinite(lower)) {
      return(upper + log(u) / slope)
    }
    log_left <- slope * (lower - upper)
    return(upper + log(exp(log_left) + u * (1 - exp(log_left))) / slope)
  }

  if (is.infinite(upper)) {
    return(lower + log1p(-u) / slope)
  }
  log_right <- slope * (upper - lower)
  lower + log1p(u * (exp(log_right) - 1)) / slope
}

.ars_sample_from_upper <- function(state, tolerance) {
  log_weights <- .ars_interval_log_weights(state, tolerance)
  max_log_weight <- max(log_weights)
  probs <- exp(log_weights - max_log_weight)
  probs <- probs / sum(probs)
  interval <- sample.int(length(probs), size = 1L, prob = probs)
  y <- .ars_sample_exp_interval(
    state$hp[interval], state$z[interval], state$z[interval + 1L], tolerance
  )
  list(x = y, interval = interval)
}

.ars_upper_value <- function(state, y, interval = NULL) {
  if (is.null(interval)) {
    interval <- findInterval(y, state$z, rightmost.closed = TRUE)
    interval <- max(1L, min(interval, length(state$x)))
  }
  state$h[interval] + state$hp[interval] * (y - state$x[interval])
}

.ars_lower_value <- function(state, y) {
  if (y < state$x[1L] || y > state$x[length(state$x)]) {
    return(-Inf)
  }

  right <- which(state$x >= y)[1L]
  if (state$x[right] == y) {
    return(state$h[right])
  }

  left <- right - 1L
  state$h[left] + (state$h[right] - state$h[left]) *
    (y - state$x[left]) / (state$x[right] - state$x[left])
}

.ars_add_support_point <- function(state, y, hy, hpy, tolerance) {
  x <- c(state$x, y)
  h <- c(state$h, hy)
  hp <- c(state$hp, hpy)
  .ars_build_state(x, h, hp, state$domain, tolerance)
}

.ars_sample_affine <- function(n, slope, domain, tolerance) {
  lower <- domain[1L]
  upper <- domain[2L]
  samples <- numeric(n)
  for (i in seq_len(n)) {
    samples[i] <- .ars_sample_exp_interval(slope, lower, upper, tolerance)
  }
  samples
}

#' Adaptive rejection sampler for univariate log-concave densities.
#'
#' @param n Number of samples to return.
#' @param density Vectorized density or log-density function. A formula,
#'   expression, or string using variable `x` is also accepted.
#' @param domain Numeric vector c(lower, upper). Infinite endpoints are allowed.
#' @param initial Optional finite support points inside the domain.
#' @param log_density TRUE if `density` already returns log-density values.
#' @param derivative Optional vectorized function returning d/dx log density.
#' @param derivative_step Step size used for numerical derivatives.
#' @param max_iter Maximum proposal attempts.
#' @param tolerance Numerical tolerance for log-concavity checks.
#' @return Numeric vector of sampled values.
ars <- function(n, density, domain = c(-Inf, Inf), initial = NULL,
                log_density = FALSE, derivative = NULL,
                derivative_step = 1e-5, max_iter = max(10000L, 100L * n),
                tolerance = 1e-8) {
  caller_env <- parent.frame()
  .ars_validate_inputs(n, density, domain, initial, derivative_step, max_iter, tolerance)

  density_function <- .ars_as_density_function(density, caller_env)
  log_density_function <- .ars_log_density_factory(density_function, log_density)
  if (is.null(initial)) {
    initial <- .ars_default_initial(domain)
  }

  x <- sort(unique(as.numeric(initial)))
  if (length(x) < 2L) {
    .ars_stop("initial support points must contain at least two distinct values.")
  }

  h <- .ars_eval_log_density(log_density_function, x)
  if (is.null(derivative)) {
    hp <- .ars_numeric_derivative(log_density_function, x, domain, derivative_step)
    derivative_function <- function(xx) {
      .ars_numeric_derivative(log_density_function, xx, domain, derivative_step)
    }
  } else {
    if (!is.function(derivative)) {
      .ars_stop("derivative must be a function when supplied.")
    }
    hp <- derivative(x)
    if (!is.numeric(hp) || length(hp) != length(x)) {
      .ars_stop("derivative must return a numeric vector with the same length as x.")
    }
    derivative_function <- derivative
  }

  .ars_check_support(x, h, hp, tolerance)
  if (.ars_is_affine_log_density(x, h, hp, tolerance)) {
    return(.ars_sample_affine(n, hp[1L], domain, tolerance))
  }

  state <- .ars_build_state(x, h, hp, domain, tolerance)
  samples <- numeric(n)
  accepted <- 0L
  attempts <- 0L

  while (accepted < n && attempts < max_iter) {
    attempts <- attempts + 1L
    proposal <- .ars_sample_from_upper(state, tolerance)
    y <- proposal$x
    upper_y <- .ars_upper_value(state, y, proposal$interval)
    lower_y <- .ars_lower_value(state, y)
    log_u <- log(runif(1L))

    accepted_by_squeeze <- is.finite(lower_y) && log_u <= (lower_y - upper_y)
    if (accepted_by_squeeze) {
      accepted <- accepted + 1L
      samples[accepted] <- y
      next
    }

    hy <- .ars_eval_log_density(log_density_function, y)
    if (!is.finite(hy)) {
      .ars_stop("density evaluated to zero or non-finite inside the domain at x = ", signif(y, 8), ".")
    }
    if (hy > upper_y + 100 * sqrt(tolerance)) {
      .ars_stop("non-log-concave density detected: log-density exceeded tangent envelope at x = ",
                signif(y, 8), ".")
    }

    hpy <- derivative_function(y)
    if (!is.numeric(hpy) || length(hpy) != 1L || !is.finite(hpy)) {
      .ars_stop("log-density derivative failed at x = ", signif(y, 8), ".")
    }

    state <- .ars_add_support_point(state, y, hy, hpy, tolerance)

    if (log_u <= (hy - upper_y)) {
      accepted <- accepted + 1L
      samples[accepted] <- y
    }
  }

  if (accepted < n) {
    .ars_stop("failed to obtain ", n, " samples within max_iter = ", max_iter, ".")
  }

  samples
}

.ars_test_line <- function(name, passed, values = NULL, target_mean = NA_real_,
                           target_sd = NA_real_) {
  sample_mean <- if (is.null(values)) NA_real_ else mean(values)
  sample_sd <- if (is.null(values)) NA_real_ else stats::sd(values)
  cat(sprintf(
    "%s: %s mean=%.4f sd=%.4f target_mean=%.4f target_sd=%.4f\n",
    name,
    if (isTRUE(passed)) "PASS" else "FAIL",
    sample_mean,
    sample_sd,
    target_mean,
    target_sd
  ))
  invisible(isTRUE(passed))
}

#' Run formal tests for the adaptive rejection sampler.
#'
#' Each test prints one line in the form `TEST_NAME: PASS ...` or
#' `TEST_NAME: FAIL ...`. The sampling tests compare stochastic output to
#' known normal and exponential moments using fixed seeds.
test <- function() {
  results <- logical()

  set.seed(1201)
  normal_samples <- ars(
    6000,
    function(x) stats::dnorm(x),
    domain = c(-Inf, Inf),
    initial = c(-2, 0, 2)
  )
  write.table(
    normal_samples,
    file = "/app/normal_samples.txt",
    row.names = FALSE,
    col.names = FALSE
  )
  normal_ok <- abs(mean(normal_samples)) < 0.06 &&
    abs(stats::sd(normal_samples) - 1) < 0.06
  results["NORMAL_SAMPLING"] <- .ars_test_line(
    "NORMAL_SAMPLING", normal_ok, normal_samples, 0, 1
  )

  set.seed(2402)
  exponential_samples <- ars(
    6000,
    function(x) stats::dexp(x, rate = 1),
    domain = c(0, Inf),
    initial = c(0.25, 1, 2)
  )
  exponential_ok <- abs(mean(exponential_samples) - 1) < 0.08 &&
    abs(stats::sd(exponential_samples) - 1) < 0.08 &&
    all(exponential_samples >= 0)
  results["EXPONENTIAL_SAMPLING"] <- .ars_test_line(
    "EXPONENTIAL_SAMPLING", exponential_ok, exponential_samples, 1, 1
  )

  invalid_n_error <- inherits(
    try(ars(-5, function(x) stats::dnorm(x)), silent = TRUE),
    "try-error"
  )
  results["INVALID_N_REJECTED"] <- .ars_test_line(
    "INVALID_N_REJECTED", invalid_n_error
  )

  invalid_domain_error <- inherits(
    try(ars(10, function(x) stats::dnorm(x), domain = c(1, 1)), silent = TRUE),
    "try-error"
  )
  results["INVALID_DOMAIN_REJECTED"] <- .ars_test_line(
    "INVALID_DOMAIN_REJECTED", invalid_domain_error
  )

  non_log_concave_error <- inherits(
    try(ars(
      10,
      function(x) exp(-x^4 + x^2),
      domain = c(-Inf, Inf),
      initial = c(-0.5, 0, 0.5),
      log_density = FALSE
    ), silent = TRUE),
    "try-error"
  )
  results["NON_LOG_CONCAVE_REJECTED"] <- .ars_test_line(
    "NON_LOG_CONCAVE_REJECTED", non_log_concave_error
  )

  log_integral <- .ars_log_interval_integral(
    slope = -1,
    intercept = 0,
    lower = 0,
    upper = Inf,
    tolerance = 1e-8
  )
  integral_ok <- abs(exp(log_integral) - 1) < 1e-10
  results["ENVELOPE_INTEGRAL"] <- .ars_test_line(
    "ENVELOPE_INTEGRAL", integral_ok
  )

  invisible(all(results))
}
